mapper.update:
UPDATE user_info
SET
    point_balance = point_balance + #{pointDelta},
    update_time = #{updateTime}
WHERE user_id = #{userId}
  AND deleted = 0

UPDATE user_info
SET
    point_balance = point_balance - #{pointDelta},
    update_time = #{updateTime}
WHERE user_id = #{userId}
  AND deleted = 0
  AND point_balance >= #{pointDelta}
